                imageUrl: "https://upload.wikimedia.org/wikipedia/commons/thumb/9/9e/David_with_the_Head_of_Goliath-Caravaggio_%281610%29.jpg/600px-David_with_the_Head_of_Goliath-Caravaggio_%281610%29.jpg",
                license: "Public Domain",
