// ── Get current week index by date ───────────────────────────────────────────
export function getCurrentWeekIndex() {
  const today = new Date();

  // Manual date map for reliability — each entry: [weekIndex, startDate, endDate]
  const schedule = [
    [0,  "2025-12-29", "2026-01-04"],
    [1,  "2026-01-05", "2026-01-11"],
    [2,  "2026-01-12", "2026-01-18"],
    [3,  "2026-01-19", "2026-01-25"],
    [4,  "2026-01-26", "2026-02-01"],
    [5,  "2026-02-02", "2026-02-08"],
    [6,  "2026-02-09", "2026-02-15"],
    [7,  "2026-02-16", "2026-02-22"],
    [8,  "2026-02-23", "2026-03-01"],
    [9,  "2026-03-02", "2026-03-08"],
    [10, "2026-03-09", "2026-03-15"],
    [11, "2026-03-16", "2026-03-22"],
    [12, "2026-03-23", "2026-03-29"],
    [13, "2026-03-30", "2026-04-05"],
    [14, "2026-04-06", "2026-04-12"],
    [15, "2026-04-13", "2026-04-19"],
    [16, "2026-04-20", "2026-04-26"],
    [17, "2026-04-27", "2026-05-03"],
    [18, "2026-05-04", "2026-05-10"],
    [19, "2026-05-11", "2026-05-17"],
    [20, "2026-05-18", "2026-05-24"],
    [21, "2026-05-25", "2026-05-31"],
    [22, "2026-06-01", "2026-06-07"],
    [23, "2026-06-08", "2026-06-14"], // Week 24 in manual, index 23
    [24, "2026-06-15", "2026-06-21"],
    [25, "2026-06-22", "2026-06-28"],
    [26, "2026-06-29", "2026-07-05"],
    [27, "2026-07-06", "2026-07-12"],
    [28, "2026-07-13", "2026-07-19"],
    [29, "2026-07-20", "2026-07-26"],
    [30, "2026-07-27", "2026-08-02"],
    [31, "2026-08-03", "2026-08-09"],
    [32, "2026-08-10", "2026-08-16"],
    [33, "2026-08-17", "2026-08-23"],
    [34, "2026-08-24", "2026-08-30"],
    [35, "2026-08-31", "2026-09-06"],
    [36, "2026-09-07", "2026-09-13"],
    [37, "2026-09-14", "2026-09-20"],
    [38, "2026-09-21", "2026-09-27"],
    [39, "2026-09-28", "2026-10-04"],
    [40, "2026-10-05", "2026-10-11"],
    [41, "2026-10-12", "2026-10-18"],
    [42, "2026-10-19", "2026-10-25"],
    [43, "2026-10-26", "2026-11-01"],
    [44, "2026-11-02", "2026-11-08"],
    [45, "2026-11-09", "2026-11-15"],
    [46, "2026-11-16", "2026-11-22"],
    [47, "2026-11-23", "2026-11-29"],
    [48, "2026-11-30", "2026-12-06"],
    [49, "2026-12-07", "2026-12-13"],
    [50, "2026-12-14", "2026-12-20"],
    [51, "2026-12-21", "2026-12-27"],
  ];

  for (const [idx, start, end] of schedule) {
    const s = new Date(start);
    const e = new Date(end);
    e.setHours(23, 59, 59);
    if (today >= s && today <= e) return idx;
  }
  return 23; // Default to current week (June 8–14)
}

export function getCurrentWeek() {
  return WEEKS[getCurrentWeekIndex()];
}
